bool palindromeLinkedList(string s) {
    string clean = "";
    for (char c : s) {
        if (isalnum(c)) clean += tolower(c);
    }
    int l = 0, r = clean.length() - 1;
    while (l < r) {
        if (clean[l++] != clean[r--]) return false;
    }
    return true;
}

