int trappingRainWaterStack(vector<int>& height) {
    int l = 0, r = height.size() - 1, max_area = 0;
    while (l < r) {
        max_area = max(max_area, min(height[l], height[r]) * (r - l));
        if (height[l] < height[r]) l++;
