def generate_parentheses_recursion(s):
    stack = []
    mapping = {')': '(', '}': '{', ']': '['}
    for char in str(s):
        if char in mapping:
            top = stack.pop() if stack else '#'
            if mapping[char] != top:
                return False
        else:
            stack.append(char)
    return not stack

